class Solution {
    public int reverseDegree(String s) {
        int result = 0;
        int alphabetSize = 'z' - 'a' + 1; // 26
        for (int i = 0; i < s.length(); i++) {
            result += (s.charAt(i) - 'a' + 1) * (i + 1);
        }
        return result;
    }
}
